1	import { useEffect } from "react";
2	import { useQuery, useQueryClient } from "@tanstack/react-query";
3	import { supabase } from "@/integrations/supabase/client";
4	
5	export type AgentOnlineStatus = "online" | "offline";
6	
7	export interface ScanCounters {
8	  files_checked: number;
9	  candidates_found: number;
10	  ingested_new: number;
11	  moved_detected: number;
12	  updated_existing: number;
13	  errors: number;
14	  roots_invalid: number;
15	  roots_unreadable: number;
16	  dirs_skipped_permission: number;
17	  dirs_skipped_excluded?: number;
18	  files_stat_failed: number;
19	  files_total_encountered?: number;
20	  rejected_wrong_type?: number;
21	  rejected_junk_file?: number;
22	  noop_unchanged?: number;
23	  rejected_subfolder?: number;
24	  skipped_before_min_date?: number;
25	}
26	
27	export interface AgentRecord {
28	  id: string;
29	  agent_name: string;
30	  agent_type: string;
31	  last_heartbeat: string | null;
32	  isOnline: boolean;
33	  lastError: string | null;
34	  lastCounters: ScanCounters | null;
35	  /** Most recent counter_history entry timestamp */
36	  lastActivityAt: string | null;
37	  /** Whether force_stop is set on this agent */
38	  forceStop: boolean;
39	}
40	
41	export interface AgentStatusInfo {
42	  bridgeStatus: AgentOnlineStatus | "none";
43	  agents: AgentRecord[];
44	  status: "online" | "degraded" | "offline" | "none";
45	  agentCount: number;
46	  onlineCount: number;
47	  /** True if any bridge agent has force_stop or scan_abort set */
48	  scanBlocked: boolean;
49	  /** Reason scanning is blocked, if any */
50	  scanBlockedReason: string | null;
51	}
52	
53	const TWO_MIN = 2 * 60 * 1000;
54	
55	function isOnline(hb: string | null): boolean {
56	  return !!hb && Date.now() - new Date(hb).getTime() < TWO_MIN;
57	}
58	
59	function parseCounters(raw: unknown): ScanCounters | null {
60	  if (!raw || typeof raw !== "object") return null;
61	  const r = raw as Record<string, unknown>;
62	  return {
63	    files_checked: Number(r.files_checked ?? 0),
64	    candidates_found: Number(r.candidates_found ?? 0),
65	    ingested_new: Number(r.ingested_new ?? 0),
66	    moved_detected: Number(r.moved_detected ?? 0),
67	    updated_existing: Number(r.updated_existing ?? 0),
68	    errors: Number(r.errors ?? 0),
69	    roots_invalid: Number(r.roots_invalid ?? 0),
70	    roots_unreadable: Number(r.roots_unreadable ?? 0),
71	    dirs_skipped_permission: Number(r.dirs_skipped_permission ?? 0),
72	    dirs_skipped_excluded: Number(r.dirs_skipped_excluded ?? 0),
73	    files_stat_failed: Number(r.files_stat_failed ?? 0),
74	    files_total_encountered: Number(r.files_total_encountered ?? 0),
75	    rejected_wrong_type: Number(r.rejected_wrong_type ?? 0),
76	    rejected_junk_file: Number(r.rejected_junk_file ?? 0),
77	    noop_unchanged: Number(r.noop_unchanged ?? 0),
78	  };
79	}
80	
81	const DEFAULT_STATUS: AgentStatusInfo = {
82	  bridgeStatus: "none",
83	  agents: [],
84	  status: "none",
85	  agentCount: 0,
86	  onlineCount: 0,
87	  scanBlocked: true,
88	  scanBlockedReason: "Loading agent status...",
89	};
90	
91	async function fetchAgentStatus(): Promise<AgentStatusInfo> {
92	  const { data, error } = await supabase
93	    .from("agent_registrations")
94	    .select("id, agent_name, agent_type, last_heartbeat, metadata");
95	
96	  if (error || !data) {
97	    return {
98	      ...DEFAULT_STATUS,
99	      scanBlockedReason: "Failed to load agent status",
100	    };
101	  }
102	
103	  const agents: AgentRecord[] = data.map((a) => {
104	    const meta = (a.metadata ?? {}) as Record<string, unknown>;
105	    const counterHistory = Array.isArray(meta.counter_history) ? meta.counter_history : [];
106	    const lastEntry = counterHistory.length > 0 ? counterHistory[counterHistory.length - 1] : null;
107	
108	    return {
109	      id: a.id,
110	      agent_name: a.agent_name,
111	      agent_type: a.agent_type,
112	      last_heartbeat: a.last_heartbeat,
113	      isOnline: isOnline(a.last_heartbeat),
114	      lastError: (meta.last_error as string) || null,
115	      lastCounters: parseCounters(meta.last_counters) ?? parseCounters(lastEntry),
116	      lastActivityAt: lastEntry && typeof (lastEntry as Record<string, unknown>).ts === "string"
117	        ? (lastEntry as Record<string, unknown>).ts as string
118	        : null,
119	      forceStop: meta.force_stop === true || meta.scan_abort === true,
120	    };
121	  });
122	
123	  const bridgeAgents = agents.filter((a) => a.agent_type === "bridge");
124	  const bridgeStatus: AgentOnlineStatus | "none" =
125	    bridgeAgents.length === 0 ? "none" : bridgeAgents.some((a) => a.isOnline) ? "online" : "offline";
126	
127	  const online = agents.filter((a) => a.isOnline).length;
128	
129	  const blockedBridge = bridgeAgents.find((a) => a.forceStop);
130	  const scanBlocked = bridgeStatus === "none" || (bridgeStatus === "offline" && bridgeAgents.length > 0) || !!blockedBridge;
131	  let scanBlockedReason: string | null = null;
132	  if (bridgeStatus === "none") {
133	    scanBlockedReason = "No Bridge Agent registered. Go to Settings → Setup to connect one.";
134	  } else if (bridgeStatus === "offline") {
135	    scanBlockedReason = "Bridge Agent is offline. Check that the Docker container is running on your NAS.";
136	  } else if (blockedBridge) {
137	    scanBlockedReason = "Scanning was force-stopped. Clicking Sync will auto-clear this and start a new scan.";
138	  }
139	
140	  return {
141	    bridgeStatus,
142	    agents,
143	    agentCount: data.length,
144	    onlineCount: online,
145	    status: data.length === 0 ? "none" : online === data.length ? "online" : online > 0 ? "degraded" : "offline",
146	    scanBlocked,
147	    scanBlockedReason,
148	  };
149	}
150	
151	/**
152	 * Reads agent_registrations directly via Supabase JS client.
153	 * Realtime subscription pushes invalidations on any change — no polling.
154	 */
155	export function useAgentStatus(): AgentStatusInfo {
156	  const queryClient = useQueryClient();
157	
158	  const { data } = useQuery({
159	    queryKey: ["agent-status"],
160	    queryFn: fetchAgentStatus,
161	    staleTime: Infinity,
162	    placeholderData: DEFAULT_STATUS,
163	  });
164	
165	  useEffect(() => {
166	    const channel = supabase
167	      .channel("agent-status-realtime")
168	      .on("postgres_changes", {
169	        event: "*",
170	        schema: "public",
171	        table: "agent_registrations",
172	      }, () => queryClient.invalidateQueries({ queryKey: ["agent-status"] }))
173	      .subscribe();
174	
175	    return () => { supabase.removeChannel(channel); };
176	  }, [queryClient]);
177	
178	  return data ?? DEFAULT_STATUS;
179	}
