33	function CopyButton({ text }: { text: string }) {
34	  const [copied, setCopied] = useState(false);
35	  const copy = () => {
36	    if (navigator.clipboard) {
37	      navigator.clipboard.writeText(text).catch(() => {
38	        prompt("Copy this value:", text);
39	      });
40	    } else {
41	      prompt("Copy this value:", text);
42	    }
43	    setCopied(true);
44	    setTimeout(() => setCopied(false), 1500);
45	  };
46	  return (
47	    <Button variant="ghost" size="icon" className="h-6 w-6 shrink-0" onClick={copy}>
