55	function AgentUpdateControls({ agentId, agentName }: { agentId: string; agentName: string }) {
56	  const { call } = useAdminApi();
57	  const queryClient = useQueryClient();
58	  const [checking, setChecking] = useState(false);
59	  const [applying, setApplying] = useState(false);
60	  const [updateStatus, setUpdateStatus] = useState<Record<string, unknown> | null>(null);
61	
62	  const pollStatus = useCallback(async (maxAttempts: number, intervalMs: number) => {
63	    for (let i = 0; i < maxAttempts; i++) {
64	      await new Promise((r) => setTimeout(r, intervalMs));
65	      try {
66	        const resp = await call("get-update-status");
67	        if (resp?.status && resp.status.reported_at) {
68	          setUpdateStatus(resp.status as Record<string, unknown>);
69	          return resp.status as Record<string, unknown>;
70	        }
71	      } catch { /* keep polling */ }
72	    }
73	    return null;
74	  }, [call]);
75	
76	  const handleCheck = async () => {
77	    setChecking(true);
78	    setUpdateStatus(null);
79	    try {
80	      await call("trigger-agent-update", { update_action: "check" });
81	      const result = await pollStatus(10, 3000);
82	      if (!result) {
83	        toast.error("Update check timed out — agent may be busy");
84	      }
85	    } catch (e) {
86	      toast.error((e as Error).message);
87	    } finally {
88	      setChecking(false);
89	    }
90	  };
91	
92	  const handleApply = async () => {
93	    setApplying(true);
94	    try {
95	      await call("trigger-agent-update", { update_action: "apply" });
96	      toast.info("Update in progress — agent will reconnect in ~30s");
97	      for (let i = 0; i < 12; i++) {
98	        await new Promise((r) => setTimeout(r, 5000));
99	        try {
100	          const resp = await call("list-agents");
101	          const agents = resp?.agents || [];
102	          const agent = agents.find((a: Record<string, unknown>) => a.id === agentId || a.name === agentName);
103	          if (agent && agent.status === "online") {
104	            toast.success("Agent updated and back online");
105	            queryClient.invalidateQueries({ queryKey: ["admin-agents"] });
106	            setUpdateStatus(null);
107	            setApplying(false);
108	            return;
109	          }
110	        } catch { /* keep polling */ }
111	      }
112	      toast.warning("Agent hasn't reconnected yet — check Container Manager");
113	    } catch (e) {
114	      toast.error((e as Error).message);
115	    } finally {
116	      setApplying(false);
117	    }
118	  };
119	
120	  const hasUpdate = updateStatus?.update_available === true;
121	  const isUpToDate = updateStatus && updateStatus.update_available === false && !updateStatus.error;
122	  const hasError = updateStatus && typeof updateStatus.error === "string";
123	
124	  return (
125	    <div className="flex items-center gap-2 flex-wrap pt-1">
126	      <Button
127	        variant="outline"
128	        size="sm"
129	        className="gap-1.5 text-xs h-7"
130	        onClick={handleCheck}
131	        disabled={checking || applying}
132	        title={applying ? "Applying update…" : checking ? "Checking for updates…" : undefined}
133	      >
134	        {checking ? <Loader2 className="h-3 w-3 animate-spin" /> : <Download className="h-3 w-3" />}
135	        Check for Update
136	      </Button>
137	
138	      {isUpToDate && (
139	        <span className="text-xs text-[hsl(var(--success))] flex items-center gap-1 font-medium">
140	          <CheckCircle2 className="h-3.5 w-3.5" /> Up to date
141	        </span>
142	      )}
143	
144	      {hasUpdate && (
145	        <>
146	          <Badge variant="secondary" className="text-xs bg-[hsl(var(--warning)/0.15)] text-[hsl(var(--warning))] border-[hsl(var(--warning)/0.3)]">
147	            Update available
148	          </Badge>
149	          <Button
150	            variant="default"
151	            size="sm"
152	            className="gap-1.5 text-xs h-7"
153	            onClick={handleApply}
154	            disabled={applying} title={applying ? "Applying update…" : undefined}
155	          >
156	            {applying ? <Loader2 className="h-3 w-3 animate-spin" /> : <Download className="h-3 w-3" />}
157	            {applying ? "Updating..." : "Apply Update"}
158	          </Button>
159	        </>
160	      )}
161	
162	      {!hasUpdate && !isUpToDate && !checking && (
163	        <Button
164	          variant="ghost"
165	          size="sm"
166	          className="gap-1.5 text-xs h-7 text-muted-foreground"
167	          onClick={handleApply}
168	          disabled={applying} title={applying ? "Applying update…" : "Reinstall the current version"}
169	        >
170	          {applying ? <Loader2 className="h-3 w-3 animate-spin" /> : <Download className="h-3 w-3" />}
171	          {applying ? "Updating..." : "Reinstall"}
172	        </Button>
173	      )}
174	
175	      {hasError && (
176	        <span className="text-xs text-destructive">{updateStatus.error as string}</span>
177	      )}
178	    </div>
179	  );
180	}
