413	function ScanCounters({ counters }: { counters: Record<string, number> }) {
414	  const totalEncountered = counters.files_total_encountered ?? 0;
415	  const supported = counters.files_checked ?? 0;
416	  const rejectedWrongType = counters.rejected_wrong_type ?? 0;
417	  const rejectedJunk = counters.rejected_junk_file ?? 0;
418	  const totalRejected = rejectedWrongType + rejectedJunk;
419	  const ingestedNew = counters.ingested_new ?? 0;
420	  const updated = counters.updated_existing ?? 0;
421	  const moved = counters.moved_detected ?? 0;
422	  const unchanged = counters.noop_unchanged ?? 0;
423	  const errors = counters.errors ?? 0;
424	  const dirsSkippedPerm = counters.dirs_skipped_permission ?? 0;
425	  const dirsSkippedExcluded = counters.dirs_skipped_excluded ?? 0;
426	  const statFailed = counters.files_stat_failed ?? 0;
427	
428	  const hasData = totalEncountered > 0 || supported > 0 || errors > 0;
429	  if (!hasData) return <p className="text-xs text-muted-foreground mt-1">No scan data yet</p>;
430	
431	  const fmt = (n: number) => n.toLocaleString();
432	
433	  return (
434	    <div className="mt-2 text-xs font-mono space-y-0.5">
435	      <div className="font-semibold text-foreground">Total files encountered: {fmt(totalEncountered)}</div>
436	      <div className="pl-3 border-l border-border ml-1 space-y-0.5">
437	        <div className="text-foreground">Supported (.ai / .psd): <span className="font-semibold">{fmt(supported)}</span></div>
438	        <div className="pl-3 border-l border-border ml-1 space-y-0.5">
439	          <div>New: <span className="text-[hsl(var(--success))]">{fmt(ingestedNew)}</span></div>
440	          <div>Updated: <span className="text-foreground">{fmt(updated)}</span></div>
441	          <div>Moved: <span className="text-foreground">{fmt(moved)}</span></div>
442	          <div>Unchanged: <span className="text-muted-foreground">{fmt(unchanged)}</span></div>
443	          <div>Errors: <span className={errors > 0 ? "text-destructive font-semibold" : "text-muted-foreground"}>{fmt(errors)}</span></div>
444	        </div>
445	      </div>
446	      <div className="pl-3 border-l border-border ml-1 space-y-0.5">
447	        <div className="text-foreground">Rejected: <span className="text-muted-foreground">{fmt(totalRejected)}</span></div>
448	        <div className="pl-3 border-l border-border ml-1 space-y-0.5">
449	          <div>Wrong type (jpg, png, etc): <span className="text-muted-foreground">{fmt(rejectedWrongType)}</span></div>
450	          <div>Junk files (._*, __MACOSX): <span className="text-muted-foreground">{fmt(rejectedJunk)}</span></div>
451	        </div>
452	      </div>
453	      <div className="pt-1 space-y-0.5">
454	        <div>Directories skipped (no permission): <span className={dirsSkippedPerm > 0 ? "text-[hsl(var(--warning))]" : "text-muted-foreground"}>{fmt(dirsSkippedPerm)}</span></div>
455	        <div>Directories skipped (excluded patterns): <span className="text-muted-foreground">{fmt(dirsSkippedExcluded)}</span></div>
456	        <div>Files failed to stat: <span className={statFailed > 0 ? "text-[hsl(var(--warning))]" : "text-muted-foreground"}>{fmt(statFailed)}</span></div>
457	      </div>
458	    </div>
459	  );
460	}
