809	      "id,root_label,relative_path,directory_path,filename,basename_no_ext,file_extension,property_folder,style_guide_folder,size_bytes,modified_at,is_active",
810	      { count: "exact" },
811	    )
812	    .eq("is_active", true)
813	    .order("style_guide_folder", { ascending: true })
814	    .order("filename", { ascending: true })
815	    .range((page - 1) * pageSize, page * pageSize - 1);
816	
817	  if (search) {
818	    query = query.ilike("filename", `%${search}%`);
819	  }
820	  if (styleGuideFolder) {
821	    query = query.eq("style_guide_folder", styleGuideFolder);
