841	    .select("file_extension")
842	    .eq("is_active", true)
843	    .not("file_extension", "is", null)
844	    .order("file_extension")
845	    .limit(100);
846	
847	  const uniqueExts = [...new Set((exts || []).map((e: { file_extension: string }) => e.file_extension))];
848	
849	  return json({
850	    ok: true,
851	    files: files || [],
852	    total: count ?? 0,
853	    page,
