982	async function handleTriggerPdfTextSample(body: Record<string, unknown>) {
983	  const db = serviceClient();
984	
985	  // If explicit asset_ids are provided, use those directly (bypasses file_type filter —
986	  // used for targeted analysis of .ai files or other non-PDF assets).
987	  const explicitIds = Array.isArray(body.asset_ids) ? (body.asset_ids as string[]) : null;
988	  if (explicitIds && explicitIds.length > 0) {
989	    const { data: assets, error } = await db
990	      .from("assets")
991	      .select("id, relative_path, filename")
992	      .in("id", explicitIds)
993	      .eq("is_deleted", false);
994	
995	    if (error) return err(error.message, 500);
996	    if (!assets || assets.length === 0) return err("None of the specified asset IDs were found", 404);
997	
998	    await db.from("admin_config").upsert({
999	      key: "PDF_TEXT_SAMPLE_REQUEST",
1000	      value: {
1001	        status: "pending",
1002	        mode: "targeted",
1003	        assets: assets.map((a) => ({ id: a.id, relative_path: a.relative_path, filename: a.filename })),
1004	        requested_at: new Date().toISOString(),
1005	      },
1006	      updated_at: new Date().toISOString(),
1007	    });
1008	
1009	    return json({ ok: true, queued: assets.length, mode: "targeted" });
1010	  }
1011	
1012	  const mode = body.mode === "full" ? "full" : "sample";
1013	
1014	  const query = db
1015	    .from("assets")
1016	    .select("id, relative_path, filename")
1017	    .eq("file_type", "pdf")
1018	    .eq("is_deleted", false);
1019	
1020	  if (mode === "sample") query.limit(250); // fetch 250 to shuffle down to 25
1021	  // full mode: no limit (Supabase default 1000; large libraries may need pagination but 1000 is sufficient)
1022	
1023	  const { data: assets, error } = await query;
1024	
1025	  if (error) return err(error.message, 500);
1026	  if (!assets || assets.length === 0) return err("No active PDF assets found", 404);
1027	
1028	  let selected = assets;
1029	  if (mode === "sample") {
1030	    // Fisher-Yates shuffle for uniform random selection
1031	    const shuffled = [...assets];
1032	    for (let i = shuffled.length - 1; i > 0; i--) {
1033	      const j = Math.floor(Math.random() * (i + 1));
1034	      [shuffled[i], shuffled[j]] = [shuffled[j], shuffled[i]];
1035	    }
1036	    selected = shuffled.slice(0, 25);
1037	  }
1038	
1039	  await db.from("admin_config").upsert({
1040	    key: "PDF_TEXT_SAMPLE_REQUEST",
1041	    value: {
1042	      status: "pending",
1043	      mode,
1044	      assets: selected.map((a) => ({ id: a.id, relative_path: a.relative_path, filename: a.filename })),
1045	      requested_at: new Date().toISOString(),
1046	    },
1047	    updated_at: new Date().toISOString(),
1048	  });
1049	
1050	  return json({ ok: true, queued: selected.length, mode });
1051	}
