13	export async function handleGenerateAgentKey(
14	  body: Record<string, unknown>,
15	  userId: string,
16	) {
17	  const agentName = requireString(body, "agent_name");
18	  const agentType = optionalString(body, "agent_type") ?? "bridge";
19	
20	  if (!["bridge", "windows-render"].includes(agentType)) {
21	    return err("agent_type must be 'bridge' or 'windows-render'");
22	  }
23	
24	  const bytes = new Uint8Array(32);
25	  crypto.getRandomValues(bytes);
26	  const rawKey = Array.from(bytes)
27	    .map((b) => b.toString(16).padStart(2, "0"))
28	    .join("");
29	
30	  const encoder = new TextEncoder();
31	  const hashBuffer = await crypto.subtle.digest("SHA-256", encoder.encode(rawKey));
32	  const hashHex = Array.from(new Uint8Array(hashBuffer))
33	    .map((b) => b.toString(16).padStart(2, "0"))
34	    .join("");
35	
36	  const db = serviceClient();
37	
38	  // Check if agent already exists — explicit select+update avoids PostgREST
39	  // schema-cache issues with upsert after adding a new UNIQUE constraint.
40	  const { data: existing } = await db
41	    .from("agent_registrations")
42	    .select("id")
43	    .eq("agent_name", agentName)
44	    .maybeSingle();
45	
46	  let data: { id: string } | null = null;
47	  let error: { message: string } | null = null;
48	
49	  if (existing) {
50	    const res = await db
51	      .from("agent_registrations")
52	      .update({ agent_type: agentType, agent_key_hash: hashHex, last_heartbeat: new Date().toISOString() })
53	      .eq("id", existing.id)
54	      .select("id")
55	      .single();
56	    data = res.data;
57	    error = res.error;
58	  } else {
59	    const res = await db
60	      .from("agent_registrations")
61	      .insert({ agent_name: agentName, agent_type: agentType, agent_key_hash: hashHex })
62	      .select("id")
63	      .single();
64	    data = res.data;
65	    error = res.error;
66	  }
67	
68	  if (error || !data) return err(error?.message || "Failed to create agent registration", 500);
69	  return json({
70	    ok: true,
71	    agent_id: data.id,
72	    agent_key: rawKey,
